// Learn: Extend a base class and call its constructor.
class Vehicle {
  Vehicle(String name) {
    this.name = name;
  }

  private final String name;
}

class Car extends Vehicle {
  Car() {
    // super calls the Vehicle constructor first.
    super("car");
  }

  @Override
  public String toString() {
    return "Car";
  }
}
